     1→'use client';
     2→
     3→import { useEffect, useRef, useState, useCallback } from 'react';
     4→import { motion } from 'framer-motion';
     5→import { Markmap } from 'markmap-view';
     6→import { Transformer } from 'markmap-lib';
     7→import { Printer, Download, ZoomIn, ZoomOut, Accessibility, RotateCcw, Maximize, Minimize } from 'lucide-react';
     8→import { cn } from '@/lib/utils';
     9→import { logger } from '@/lib/logger';
    10→import { useAccessibilityStore } from '@/lib/accessibility/accessibility-store';
    11→
    12→// Node structure for programmatic mindmap creation
    13→export interface MindmapNode {
    14→  id: string;
    15→  label: string;
    16→  children?: MindmapNode[];
    17→  icon?: string;
    18→  color?: string;
    19→}
    20→
    21→// Props can accept either markdown string OR structured nodes
    22→export interface MarkMapRendererProps {
    23→  title: string;
    24→  markdown?: string;
    25→  nodes?: MindmapNode[];
    26→  className?: string;
    27→}
    28→
    29→// Transformer instance for markdown parsing
    30→const transformer = new Transformer();
    31→
    32→// Convert structured nodes to markdown format
    33→function nodesToMarkdown(nodes: MindmapNode[], title: string): string {
    34→  const buildMarkdown = (node: MindmapNode, depth: number): string => {
    35→    const prefix = '#'.repeat(depth + 1);
    36→    let result = `${prefix} ${node.label}\n`;
    37→
    38→    if (node.children && node.children.length > 0) {
    39→      for (const child of node.children) {
    40→        result += buildMarkdown(child, depth + 1);
    41→      }
    42→    }
    43→
    44→    return result;
    45→  };
    46→
    47→  let markdown = `# ${title}\n`;
    48→  for (const node of nodes) {
    49→    markdown += buildMarkdown(node, 1);
    50→  }
    51→
    52→  return markdown;
    53→}
    54→
    55→export function MarkMapRenderer({ title, markdown, nodes, className }: MarkMapRendererProps) {
    56→  const svgRef = useRef<SVGSVGElement>(null);
    57→  const containerRef = useRef<HTMLDivElement>(null);
    58→  const markmapRef = useRef<Markmap | null>(null);
    59→  const [error, setError] = useState<string | null>(null);
    60→  const [rendered, setRendered] = useState(false);
    61→  const [zoom, setZoom] = useState(1);
    62→  const [accessibilityMode, setAccessibilityMode] = useState(false);
    63→  const [isFullscreen, setIsFullscreen] = useState(false);
    64→
    65→  const { settings } = useAccessibilityStore();
    66→
    67→  // Get the markdown content
    68→  const getMarkdownContent = useCallback((): string => {
    69→    if (markdown) {
    70→      return markdown;
    71→    }
    72→    if (nodes && nodes.length > 0) {
    73→      return nodesToMarkdown(nodes, title);
    74→    }
    75→    return `# ${title}\n## No content`;
    76→  }, [markdown, nodes, title]);
    77→
    78→  // Generate accessible description
    79→  const generateTextDescription = useCallback((): string => {
    80→    if (nodes && nodes.length > 0) {
    81→      const describeNode = (node: MindmapNode): string => {
    82→        let desc = node.label;
    83→        if (node.children && node.children.length > 0) {
    84→          desc += ': ' + node.children.map(c => describeNode(c)).join(', ');
    85→        }
    86→        return desc;
    87→      };
    88→      return `${title} con i seguenti rami: ${nodes.map(n => describeNode(n)).join('; ')}`;
    89→    }
    90→    return `Mappa mentale: ${title}`;
    91→  }, [nodes, title]);
    92→
    93→  // Render mindmap
    94→  useEffect(() => {
    95→    const renderMindmap = async () => {
    96→      if (!svgRef.current) return;
    97→
    98→      try {
    99→        setError(null);
   100→        setRendered(false);
   101→
   102→        // Clear previous content
   103→        svgRef.current.innerHTML = '';
   104→
   105→        // Get markdown and transform to markmap data
   106→        const content = getMarkdownContent();
   107→        const { root } = transformer.transform(content);
   108→
   109→        // Determine font family based on accessibility settings
   110→        const fontFamily = settings.dyslexiaFont || accessibilityMode
   111→          ? 'OpenDyslexic, Comic Sans MS, sans-serif'
   112→          : 'Arial, Helvetica, sans-serif';
   113→
   114→        // Determine colors based on accessibility settings
   115→        const isHighContrast = settings.highContrast || accessibilityMode;
   116→
   117→        // Create or update markmap
   118→        if (markmapRef.current) {
   119→          markmapRef.current.destroy();
   120→        }
   121→
   122→        markmapRef.current = Markmap.create(svgRef.current, {
   123→          autoFit: true,
   124→          duration: 300,
   125→          maxWidth: 280,
   126→          paddingX: 16,
   127→          spacingVertical: 8,
   128→          spacingHorizontal: 100,
   129→          initialExpandLevel: 3, // Start with first 3 levels expanded, rest collapsed
   130→          zoom: true, // Enable zoom/pan
   131→          pan: true,  // Enable panning
   132→          color: (node) => {
   133→            if (isHighContrast) {
   134→              // High contrast colors
   135→              const colors = ['#ffff00', '#00ffff', '#ff00ff', '#00ff00', '#ff8000'];
   136→              return colors[node.state?.depth % colors.length] || '#ffffff';
   137→            }
   138→            // Normal theme colors
   139→            const colors = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];
   140→            return colors[node.state?.depth % colors.length] || '#64748b';
   141→          },
   142→        }, root);
   143→
   144→        // Apply custom styles after render
   145→        setTimeout(() => {
   146→          if (svgRef.current) {
   147→            // Apply font to all text elements
   148→            const textElements = svgRef.current.querySelectorAll('text, foreignObject');
   149→            textElements.forEach((el) => {
   150→              if (el instanceof SVGElement || el instanceof HTMLElement) {
   151→                el.style.fontFamily = fontFamily;
   152→                if (settings.largeText) {
   153→                  el.style.fontSize = '16px';
   154→                }
   155→              }
   156→            });
   157→
   158→            // High contrast background
   159→            if (isHighContrast) {
   160→              const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
   161→              rect.setAttribute('width', '100%');
   162→              rect.setAttribute('height', '100%');
   163→              rect.setAttribute('fill', '#000000');
   164→              svgRef.current.insertBefore(rect, svgRef.current.firstChild);
   165→            }
   166→          }
   167→        }, 100);
   168→
   169→        // Add ARIA attributes
   170→        svgRef.current.setAttribute('role', 'img');
   171→        svgRef.current.setAttribute('aria-label', `Mappa mentale: ${title}`);
   172→
   173→        // Add title and desc for screen readers
   174→        const titleEl = document.createElementNS('http://www.w3.org/2000/svg', 'title');
   175→        titleEl.textContent = `Mappa mentale: ${title}`;
   176→        svgRef.current.insertBefore(titleEl, svgRef.current.firstChild);
   177→
   178→        const descEl = document.createElementNS('http://www.w3.org/2000/svg', 'desc');
   179→        descEl.textContent = generateTextDescription();
   180→        svgRef.current.insertBefore(descEl, svgRef.current.firstChild?.nextSibling || null);
   181→
   182→        setRendered(true);
   183→      } catch (err) {
   184→        const errorMsg = err instanceof Error ? err.message : String(err);
   185→        setError(errorMsg);
   186→        logger.error('MarkMap render error', { error: String(err) });
   187→      }
   188→    };
   189→
   190→    renderMindmap();
   191→  }, [markdown, nodes, title, settings.dyslexiaFont, settings.highContrast, settings.largeText, accessibilityMode, getMarkdownContent, generateTextDescription]);
   192→
   193→  // Zoom controls
   194→  const handleZoomIn = useCallback(() => {
   195→    if (markmapRef.current) {
   196→      markmapRef.current.rescale(1.25);
   197→    }
   198→    setZoom(z => Math.min(z * 1.25, 3));
   199→  }, []);
   200→
   201→  const handleZoomOut = useCallback(() => {
   202→    if (markmapRef.current) {
   203→      markmapRef.current.rescale(0.8);
   204→    }
   205→    setZoom(z => Math.max(z * 0.8, 0.5));
   206→  }, []);
   207→
   208→  const handleReset = useCallback(() => {
   209→    if (markmapRef.current) {
   210→      markmapRef.current.fit();
   211→    }
   212→    setZoom(1);
   213→  }, []);
   214→
   215→  // Fullscreen toggle
   216→  const handleFullscreen = useCallback(async () => {
   217→    if (!containerRef.current) return;
   218→
   219→    try {
   220→      if (!document.fullscreenElement) {
   221→        await containerRef.current.requestFullscreen();
   222→        setIsFullscreen(true);
   223→      } else {
   224→        await document.exitFullscreen();
   225→        setIsFullscreen(false);
   226→      }
   227→    } catch (err) {
   228→      logger.error('Fullscreen error', { error: String(err) });
   229→    }
   230→  }, []);
   231→
   232→  // Listen for fullscreen changes (user may exit with Escape)
   233→  useEffect(() => {
   234→    const handleFullscreenChange = () => {
   235→      setIsFullscreen(!!document.fullscreenElement);
   236→      // Re-fit the mindmap when entering/exiting fullscreen
   237→      if (markmapRef.current) {
   238→        setTimeout(() => markmapRef.current?.fit(), 100);
   239→      }
   240→    };
   241→
   242→    document.addEventListener('fullscreenchange', handleFullscreenChange);
   243→    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
   244→  }, []);
   245→
   246→  // Print functionality - expands labels to prevent truncation
   247→  const handlePrint = useCallback(() => {
   248→    if (!svgRef.current) return;
   249→
   250→    const printWindow = window.open('', '_blank');
   251→    if (!printWindow) return;
   252→
   253→    const svgClone = svgRef.current.cloneNode(true) as SVGSVGElement;
   254→
   255→    // Fix truncated labels: expand all foreignObject elements to fit their content
   256→    const foreignObjects = svgClone.querySelectorAll('foreignObject');
   257→    foreignObjects.forEach((fo) => {
   258→      // Remove width constraint to let text flow naturally
   259→      fo.setAttribute('width', '600'); // Expanded width for printing
   260→      // Also update any nested div with max-width
   261→      const divs = fo.querySelectorAll('div');
   262→      divs.forEach((div) => {
   263→        if (div instanceof HTMLElement) {
   264→          div.style.maxWidth = 'none';
   265→          div.style.width = 'auto';
   266→          div.style.whiteSpace = 'nowrap';
   267→          div.style.overflow = 'visible';
   268→        }
   269→      });
   270→    });
   271→
   272→    // Expand the SVG viewBox to accommodate wider labels
   273→    const bbox = svgRef.current.getBBox();
   274→    const expandedWidth = Math.max(bbox.width * 1.5, 1600);
   275→    const expandedHeight = Math.max(bbox.height + 200, 1000);
   276→    svgClone.setAttribute('width', String(expandedWidth));
   277→    svgClone.setAttribute('height', String(expandedHeight));
   278→    svgClone.setAttribute('viewBox', `${bbox.x - 100} ${bbox.y - 50} ${expandedWidth} ${expandedHeight}`);
   279→
   280→    const svgString = new XMLSerializer().serializeToString(svgClone);
   281→
   282→    printWindow.document.write(`
   283→      <!DOCTYPE html>
   284→      <html>
   285→        <head>
   286→          <title>Mappa Mentale: ${title}</title>
   287→          <style>
   288→            @import url('https://fonts.cdnfonts.com/css/opendyslexic');
   289→
   290→            * {
   291→              box-sizing: border-box;
   292→              margin: 0;
   293→              padding: 0;
   294→            }
   295→
   296→            html, body {
   297→              width: 100%;
   298→              height: 100%;
   299→              margin: 0;
   300→              padding: 0;
   301→              font-family: ${settings.dyslexiaFont ? 'OpenDyslexic, ' : ''}Arial, sans-serif;
   302→              background: white;
   303→            }
   304→
   305→            .print-page {
   306→              width: 100%;
   307→              height: 100vh;
   308→              display: flex;
   309→              flex-direction: column;
   310→              padding: 10mm;
   311→            }
   312→
   313→            h1 {
   314→              text-align: center;
   315→              font-size: ${settings.largeText ? '24pt' : '18pt'};
   316→              margin-bottom: 8mm;
   317→              flex-shrink: 0;
   318→            }
   319→
   320→            .mindmap-container {
   321→              flex: 1;
   322→              display: flex;
   323→              justify-content: center;
   324→              align-items: center;
   325→              overflow: visible;
   326→              min-height: 0;
   327→            }
   328→
   329→            .mindmap-container svg {
   330→              max-width: 100%;
   331→              max-height: 100%;
   332→              width: auto;
   333→              height: auto;
   334→              overflow: visible;
   335→            }
   336→
   337→            /* Ensure all text is visible */
   338→            foreignObject { overflow: visible !important; }
   339→            foreignObject div {
   340→              max-width: none !important;
   341→              white-space: nowrap !important;
   342→              overflow: visible !important;
   343→            }
   344→
   345→            @media print {
   346→              @page {
   347→                size: A4 landscape;
   348→                margin: 5mm;
   349→              }
   350→
   351→              html, body {
   352→                -webkit-print-color-adjust: exact;
   353→                print-color-adjust: exact;
   354→              }
   355→
   356→              .print-page {
   357→                height: 100%;
   358→                page-break-after: avoid;
   359→                padding: 5mm;
   360→              }
   361→
   362→              h1 {
   363→                font-size: ${settings.largeText ? '20pt' : '16pt'};
   364→                margin-bottom: 5mm;
   365→              }
   366→            }
   367→          </style>
   368→        </head>
   369→        <body>
   370→          <div class="print-page">
   371→            <h1>${title}</h1>
   372→            <div class="mindmap-container">${svgString}</div>
   373→          </div>
   374→          <script>
   375→            window.onload = function() {
   376→              setTimeout(function() { window.print(); window.close(); }, 500);
   377→            };
   378→          </script>
   379→        </body>
   380→      </html>
   381→    `);
   382→    printWindow.document.close();
   383→  }, [title, settings.dyslexiaFont, settings.largeText]);
   384→
   385→  // Download as PNG - expands labels to prevent truncation
   386→  const handleDownload = useCallback(async () => {
   387→    if (!svgRef.current) return;
   388→
   389→    try {
   390→      const svgClone = svgRef.current.cloneNode(true) as SVGSVGElement;
   391→
   392→      // Fix truncated labels: expand all foreignObject elements to fit their content
   393→      const foreignObjects = svgClone.querySelectorAll('foreignObject');
   394→      foreignObjects.forEach((fo) => {
   395→        fo.setAttribute('width', '600'); // Expanded width for download
   396→        const divs = fo.querySelectorAll('div');
   397→        divs.forEach((div) => {
   398→          if (div instanceof HTMLElement) {
   399→            div.style.maxWidth = 'none';
   400→            div.style.width = 'auto';
   401→            div.style.whiteSpace = 'nowrap';
   402→            div.style.overflow = 'visible';
   403→          }
   404→        });
   405→      });
   406→
   407→      // Get dimensions with extra space for expanded labels
   408→      const bbox = svgRef.current.getBBox();
   409→      const width = Math.max(bbox.width * 1.5, 2000);
   410→      const height = Math.max(bbox.height + 200, 1200);
   411→
   412→      svgClone.setAttribute('width', String(width));
   413→      svgClone.setAttribute('height', String(height));
   414→      svgClone.setAttribute('viewBox', `${bbox.x - 100} ${bbox.y - 50} ${width} ${height}`);
   415→
   416→      // Inline styles
   417→      const allElements = svgClone.querySelectorAll('*');
   418→      allElements.forEach((el) => {
   419→        if (el instanceof SVGElement || el instanceof HTMLElement) {
   420→          const computed = window.getComputedStyle(el);
   421→          ['fill', 'stroke', 'stroke-width', 'font-family', 'font-size', 'font-weight'].forEach((prop) => {
   422→            const value = computed.getPropertyValue(prop);
   423→            if (value && value !== 'none' && value !== 'initial') {
   424→              (el as HTMLElement).style.setProperty(prop, value);
   425→            }
   426→          });
   427→        }
   428→      });
   429→
   430→      // Create canvas
   431→      const canvas = document.createElement('canvas');
   432→      canvas.width = width;
   433→      canvas.height = height;
   434→      const ctx = canvas.getContext('2d');
   435→      if (!ctx) return;
   436→
   437→      // White background
   438→      ctx.fillStyle = '#ffffff';
   439→      ctx.fillRect(0, 0, width, height);
   440→
   441→      // SVG to data URL
   442→      const serializer = new XMLSerializer();
   443→      let svgString = serializer.serializeToString(svgClone);
   444→      if (!svgString.includes('xmlns=')) {
   445→        svgString = svgString.replace('<svg', '<svg xmlns="http://www.w3.org/2000/svg"');
   446→      }
   447→
   448→      const base64 = btoa(unescape(encodeURIComponent(svgString)));
   449→      const dataUrl = `data:image/svg+xml;base64,${base64}`;
   450→
   451→      const img = new Image();
   452→      img.crossOrigin = 'anonymous';
   453→
   454→      img.onload = () => {
   455→        ctx.drawImage(img, 0, 0, width, height);
   456→        canvas.toBlob((blob) => {
   457→          if (!blob) return;
   458→          const url = URL.createObjectURL(blob);
   459→          const a = document.createElement('a');
   460→          a.href = url;
   461→          a.download = `mappa-mentale-${title.toLowerCase().replace(/\s+/g, '-')}.png`;
   462→          document.body.appendChild(a);
   463→          a.click();
   464→          document.body.removeChild(a);
   465→          URL.revokeObjectURL(url);
   466→        }, 'image/png');
   467→      };
   468→
   469→      img.onerror = () => {
   470→        // Fallback: download SVG
   471→        const svgBlob = new Blob([svgString], { type: 'image/svg+xml' });
   472→        const url = URL.createObjectURL(svgBlob);
   473→        const a = document.createElement('a');
   474→        a.href = url;
   475→        a.download = `mappa-mentale-${title.toLowerCase().replace(/\s+/g, '-')}.svg`;
   476→        document.body.appendChild(a);
   477→        a.click();
   478→        document.body.removeChild(a);
   479→        URL.revokeObjectURL(url);
   480→      };
   481→
   482→      img.src = dataUrl;
   483→    } catch (err) {
   484→      logger.error('Export error', { error: String(err) });
   485→    }
   486→  }, [title]);
   487→
   488→  return (
   489→    <motion.div
   490→      ref={containerRef}
   491→      initial={{ opacity: 0, scale: 0.95 }}
   492→      animate={{ opacity: 1, scale: 1 }}
   493→      className={cn(
   494→        'rounded-xl border overflow-hidden',
   495→        settings.highContrast
   496→          ? 'border-white bg-black'
   497→          : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800',
   498→        isFullscreen && 'fixed inset-0 z-50 rounded-none',
   499→        className
   500→      )}
   501→      role="region"
   502→      aria-label={`Mappa mentale: ${title}`}
   503→    >
   504→      {/* Toolbar */}
   505→      <div
   506→        className={cn(
   507→          'flex items-center justify-between px-4 py-2 border-b',
   508→          settings.highContrast
   509→            ? 'border-white bg-black'
   510→            : 'border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50'
   511→        )}
   512→      >
   513→        <h3
   514→          className={cn(
   515→            'font-semibold',
   516→            settings.dyslexiaFont && 'tracking-wide',
   517→            settings.highContrast ? 'text-yellow-400' : 'text-slate-700 dark:text-slate-200'
   518→          )}
   519→          style={{ fontSize: `${14 * (settings.largeText ? 1.2 : 1)}px` }}
   520→        >
   521→          {title}
   522→        </h3>
   523→
   524→        <div className="flex items-center gap-2">
   525→          {/* Accessibility toggle */}
   526→          <button
   527→            onClick={() => setAccessibilityMode(!accessibilityMode)}
   528→            className={cn(
   529→              'p-2 rounded-lg transition-colors',
   530→              accessibilityMode
   531→                ? 'bg-accent-themed text-white'
   532→                : settings.highContrast
   533→                  ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   534→                  : 'bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600'
   535→            )}
   536→            title="Modalita accessibilita"
   537→            aria-label="Attiva/disattiva modalita accessibilita"
   538→          >
   539→            <Accessibility className="w-4 h-4" />
   540→          </button>
   541→
   542→          {/* Reset view */}
   543→          <button
   544→            onClick={handleReset}
   545→            className={cn(
   546→              'p-2 rounded-lg transition-colors',
   547→              settings.highContrast
   548→                ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   549→                : 'bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600'
   550→            )}
   551→            title="Ripristina vista"
   552→            aria-label="Ripristina vista"
   553→          >
   554→            <RotateCcw className="w-4 h-4" />
   555→          </button>
   556→
   557→          {/* Zoom controls */}
   558→          <button
   559→            onClick={handleZoomOut}
   560→            className={cn(
   561→              'p-2 rounded-lg transition-colors',
   562→              settings.highContrast
   563→                ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   564→                : 'bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600'
   565→            )}
   566→            title="Riduci zoom"
   567→            aria-label="Riduci zoom"
   568→          >
   569→            <ZoomOut className="w-4 h-4" />
   570→          </button>
   571→
   572→          <span
   573→            className={cn(
   574→              'text-sm min-w-[4rem] text-center',
   575→              settings.highContrast ? 'text-white' : 'text-slate-600 dark:text-slate-400'
   576→            )}
   577→          >
   578→            {Math.round(zoom * 100)}%
   579→          </span>
   580→
   581→          <button
   582→            onClick={handleZoomIn}
   583→            className={cn(
   584→              'p-2 rounded-lg transition-colors',
   585→              settings.highContrast
   586→                ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   587→                : 'bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600'
   588→            )}
   589→            title="Aumenta zoom"
   590→            aria-label="Aumenta zoom"
   591→          >
   592→            <ZoomIn className="w-4 h-4" />
   593→          </button>
   594→
   595→          {/* Fullscreen toggle */}
   596→          <button
   597→            onClick={handleFullscreen}
   598→            className={cn(
   599→              'p-2 rounded-lg transition-colors',
   600→              isFullscreen
   601→                ? 'bg-green-500 text-white hover:bg-green-600'
   602→                : settings.highContrast
   603→                  ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   604→                  : 'bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600'
   605→            )}
   606→            title={isFullscreen ? 'Esci da schermo intero' : 'Schermo intero'}
   607→            aria-label={isFullscreen ? 'Esci da schermo intero' : 'Schermo intero'}
   608→          >
   609→            {isFullscreen ? <Minimize className="w-4 h-4" /> : <Maximize className="w-4 h-4" />}
   610→          </button>
   611→
   612→          {/* Download */}
   613→          <button
   614→            onClick={handleDownload}
   615→            className={cn(
   616→              'p-2 rounded-lg transition-colors',
   617→              settings.highContrast
   618→                ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   619→                : 'bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600'
   620→            )}
   621→            title="Scarica PNG"
   622→            aria-label="Scarica mappa come PNG"
   623→          >
   624→            <Download className="w-4 h-4" />
   625→          </button>
   626→
   627→          {/* Print */}
   628→          <button
   629→            onClick={handlePrint}
   630→            className={cn(
   631→              'p-2 rounded-lg transition-colors',
   632→              settings.highContrast
   633→                ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   634→                : 'bg-accent-themed text-white hover:brightness-110'
   635→            )}
   636→            title="Stampa"
   637→            aria-label="Stampa mappa mentale"
   638→          >
   639→            <Printer className="w-4 h-4" />
   640→          </button>
   641→        </div>
   642→      </div>
   643→
   644→      {/* Mindmap container - centered with pan/zoom support */}
   645→      <div
   646→        className={cn(
   647→          'flex items-center justify-center overflow-hidden relative',
   648→          settings.highContrast ? 'bg-black' : 'bg-white dark:bg-slate-900',
   649→          isFullscreen && 'flex-1'
   650→        )}
   651→        style={{
   652→          height: isFullscreen ? 'calc(100vh - 60px)' : '500px',
   653→          minHeight: isFullscreen ? 'calc(100vh - 60px)' : '400px'
   654→        }}
   655→      >
   656→        {error ? (
   657→          <div
   658→            className={cn(
   659→              'p-4 rounded-lg text-sm',
   660→              settings.highContrast
   661→                ? 'bg-red-900 border-2 border-red-500 text-white'
   662→                : 'bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400'
   663→            )}
   664→            role="alert"
   665→          >
   666→            <strong>Errore:</strong> {error}
   667→          </div>
   668→        ) : (
   669→          <>
   670→            <svg
   671→              ref={svgRef}
   672→              className={cn(
   673→                'absolute inset-0 w-full h-full cursor-grab active:cursor-grabbing',
   674→                !rendered && 'animate-pulse rounded-lg',
   675→                !rendered && (settings.highContrast ? 'bg-gray-800' : 'bg-slate-100 dark:bg-slate-700/50')
   676→              )}
   677→              style={{ touchAction: 'none' }}
   678→            />
   679→            {rendered && (
   680→              <div className="absolute bottom-2 left-2 text-xs text-slate-400 dark:text-slate-500 pointer-events-none select-none">
   681→                Trascina per spostare • Scroll/pinch per zoom • Click sui nodi per espandere/comprimere
   682→              </div>
   683→            )}
   684→          </>
   685→        )}
   686→      </div>
   687→
   688→      {/* Screen reader description */}
   689→      <div className="sr-only" aria-live="polite">
   690→        {rendered && `Mappa mentale "${title}" renderizzata con successo.`}
   691→      </div>
   692→    </motion.div>
   693→  );
   694→}
   695→
   696→// Helper to create mindmap from topics (same interface as before)
   697→export function createMindmapFromTopics(
   698→  title: string,
   699→  topics: Array<{ name: string; subtopics?: string[] }>
   700→): { title: string; nodes: MindmapNode[] } {
   701→  return {
   702→    title,
   703→    nodes: topics.map((topic, i) => ({
   704→      id: `topic-${i}`,
   705→      label: topic.name,
   706→      children: topic.subtopics?.map((sub, j) => ({
   707→        id: `topic-${i}-sub-${j}`,
   708→        label: sub,
   709→      })),
   710→    })),
   711→  };
   712→}
   713→
   714→// Helper to create mindmap from markdown
   715→export function createMindmapFromMarkdown(
   716→  title: string,
   717→  markdown: string
   718→): { title: string; markdown: string } {
   719→  return { title, markdown };
   720→}
   721→
   722→// Backward compatibility alias (old name was MindmapRenderer)
   723→export { MarkMapRenderer as MindmapRenderer };
   724→
   725→// Example mindmaps for testing
   726→export const exampleMindmaps = {
