   728→    { name: 'Algebra', subtopics: ['Equazioni di primo grado', 'Equazioni di secondo grado', 'Polinomi e fattorizzazione'] },
   729→    { name: 'Geometria', subtopics: ['Triangoli e proprieta', 'Cerchi e circonferenze', 'Solidi geometrici'] },
   730→    { name: 'Analisi', subtopics: ['Limiti e continuita', 'Derivate e applicazioni', 'Integrali definiti'] },
   731→  ]),
