          type: 'string',
          description: 'Il commento/feedback per lo studente',
        },
      },
      required: ['sectionId', 'startOffset', 'endOffset', 'text'],
    },
  },
  {
    type: 'function',
    name: 'create_diagram',
    description:
      'Crea un diagramma (flowchart, sequence, class, ER). Usalo per processi, algoritmi, relazioni tra entità.',
    parameters: {
      type: 'object',
      properties: {
