          children: [
            { id: '2', label: 'Child' },
          ],
        },
      ];

      const flat = convertChildrenToParentId(tree);

      expect(flat).toHaveLength(2);
      expect(flat[0]).toEqual({ id: '1', label: 'Root', parentId: null });
      expect(flat[1]).toEqual({ id: '2', label: 'Child', parentId: '1' });
    });
  });

