    it('should generate proper markdown hierarchy', () => {
      const flat = [
        { id: '1', label: 'Geografia', parentId: null },
        { id: '2', label: 'Posizione', parentId: '1' },
        { id: '3', label: 'Nord-Ovest', parentId: '2' },
