    89→
    90→export function MindmapsView({ className }: MindmapsViewProps) {
    91→  const _router = useRouter();
    92→  const { enterFocusMode } = useUIStore();
    93→
    94→  // Load saved mindmaps from database API
    95→  const { mindmaps, loading, saveMindmap, deleteMindmap: apiDeleteMindmap, reload: _reload } = useMindmaps();
    96→
    97→  const [selectedMindmap, setSelectedMindmap] = useState<SavedMindmap | null>(null);
    98→  const [showExamples, setShowExamples] = useState(false);
    99→  const [selectedExample, setSelectedExample] = useState<{ title: string; nodes: MindmapNode[]; subject: string } | null>(null);
   100→  const [showCreateModal, setShowCreateModal] = useState(false);
   101→  const [newMapTitle, setNewMapTitle] = useState('');
   102→  const [newMapSubject, setNewMapSubject] = useState<Subject>('mathematics');
   103→  const [newMapTopics, setNewMapTopics] = useState<{ name: string; subtopics: string[] }[]>([
   104→    { name: '', subtopics: [''] },
   105→  ]);
   106→  const [showMaestroDialog, setShowMaestroDialog] = useState(false);
   107→
   108→  // Handle maestro selection and enter focus mode
   109→  const handleMaestroConfirm = useCallback((maestro: Maestro, mode: 'voice' | 'chat') => {
   110→    setShowMaestroDialog(false);
   111→    enterFocusMode('mindmap', maestro.id, mode);
   112→  }, [enterFocusMode]);
   113→
   114→  // Delete mindmap via API
   115→  const handleDeleteMindmap = async (id: string) => {
   116→    await apiDeleteMindmap(id);
   117→    if (selectedMindmap?.id === id) {
   118→      setSelectedMindmap(null);
   119→    }
   120→  };
   121→
   122→  // Save example as personal mindmap
   123→  const saveExampleAsMindmap = async (example: { title: string; nodes: MindmapNode[] }, subject: string) => {
   124→    await saveMindmap({
   125→      title: example.title,
   126→      nodes: example.nodes,
   127→      subject: subject as Subject,
   128→    });
   129→    setSelectedExample(null);
   130→    setShowExamples(false);
   131→  };
   132→
   133→  // Create new mindmap from form
   134→  const handleCreateMindmap = async () => {
   135→    if (!newMapTitle.trim()) return;
   136→
   137→    const validTopics = newMapTopics.filter(t => t.name.trim());
   138→    if (validTopics.length === 0) return;
   139→
   140→    const { nodes } = createMindmapFromTopics(
   141→      newMapTitle,
   142→      validTopics.map(t => ({
   143→        name: t.name,
   144→        subtopics: t.subtopics.filter(s => s.trim()),
   145→      }))
   146→    );
   147→
   148→    await saveMindmap({
   149→      title: newMapTitle,
   150→      nodes,
   151→      subject: newMapSubject,
   152→    });
   153→
   154→    setShowCreateModal(false);
   155→    setNewMapTitle('');
   156→    setNewMapSubject('mathematics');
   157→    setNewMapTopics([{ name: '', subtopics: [''] }]);
   158→  };
   159→
   160→  // Add topic to creation form
   161→  const addTopic = () => {
   162→    setNewMapTopics([...newMapTopics, { name: '', subtopics: [''] }]);
   163→  };
   164→
   165→  // Update topic name
   166→  const updateTopicName = (index: number, name: string) => {
   167→    const updated = [...newMapTopics];
   168→    updated[index].name = name;
   169→    setNewMapTopics(updated);
   170→  };
   171→
   172→  // Add subtopic
   173→  const addSubtopic = (topicIndex: number) => {
   174→    const updated = [...newMapTopics];
   175→    updated[topicIndex].subtopics.push('');
   176→    setNewMapTopics(updated);
   177→  };
   178→
   179→  // Update subtopic
   180→  const updateSubtopic = (topicIndex: number, subtopicIndex: number, value: string) => {
   181→    const updated = [...newMapTopics];
   182→    updated[topicIndex].subtopics[subtopicIndex] = value;
   183→    setNewMapTopics(updated);
   184→  };
   185→
   186→  // Remove topic
   187→  const removeTopic = (index: number) => {
   188→    if (newMapTopics.length > 1) {
   189→      setNewMapTopics(newMapTopics.filter((_, i) => i !== index));
   190→    }
   191→  };
   192→
   193→  // Remove subtopic
   194→  const removeSubtopic = (topicIndex: number, subtopicIndex: number) => {
   195→    const updated = [...newMapTopics];
   196→    if (updated[topicIndex].subtopics.length > 1) {
   197→      updated[topicIndex].subtopics = updated[topicIndex].subtopics.filter((_, i) => i !== subtopicIndex);
   198→      setNewMapTopics(updated);
   199→    }
   200→  };
   201→
   202→  // Group mindmaps by subject
   203→  const mindmapsBySubject = useMemo(() => {
   204→    const grouped: Record<string, SavedMindmap[]> = {};
   205→    mindmaps.forEach(m => {
   206→      if (!grouped[m.subject]) grouped[m.subject] = [];
   207→      grouped[m.subject].push(m);
   208→    });
   209→    return grouped;
   210→  }, [mindmaps]);
   211→
   212→  // Close any open modal
   213→  const closeModals = useCallback(() => {
   214→    setSelectedMindmap(null);
   215→    setShowExamples(false);
   216→    setSelectedExample(null);
   217→    setShowCreateModal(false);
   218→  }, []);
   219→
   220→  // Handle export mindmap
   221→  const handleExport = useCallback(async (mindmap: SavedMindmap, format: ExportFormat) => {
   222→    try {
   223→      // Convert SavedMindmap to MindmapData format
   224→      const mindmapData = {
   225→        title: mindmap.title,
   226→        topic: mindmap.subject,
   227→        root: {
   228→          id: 'root',
   229→          text: mindmap.title,
   230→          children: mindmap.nodes.map((node) => ({
   231→            id: node.id,
   232→            text: node.label,
   233→            color: node.color,
   234→            children: node.children?.map((child) => ({
   235→              id: child.id,
   236→              text: child.label,
   237→              color: child.color,
   238→            })),
   239→          })),
   240→        },
   241→        createdAt: mindmap.createdAt.toString(),
   242→        updatedAt: new Date().toISOString(),
   243→      };
   244→
   245→      const result = await exportMindmap(mindmapData, { format });
   246→      downloadExport(result);
   247→      logger.info('Mindmap exported', { format, title: mindmap.title });
   248→    } catch (error) {
   249→      logger.error('Export failed', { error });
   250→      alert(`Errore durante l'esportazione: ${error instanceof Error ? error.message : 'Errore sconosciuto'}`);
   251→    }
   252→  }, []);
   253→
   254→  // Handle import mindmap
   255→  const handleImport = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
   256→    const file = event.target.files?.[0];
   257→    if (!file) return;
   258→
   259→    try {
   260→      const result = await importMindmapFromFile(file);
   261→
   262→      if (!result.success || !result.mindmap) {
   263→        throw new Error(result.error || 'Import failed');
   264→      }
   265→
   266→      // Convert MindmapData to SavedMindmap format
   267→      const convertNode = (node: { id: string; text: string; color?: string; children?: unknown[] }): MindmapNode => ({
   268→        id: node.id,
   269→        label: node.text,
   270→        color: node.color,
   271→        children: node.children?.map((child) => convertNode(child as { id: string; text: string; color?: string; children?: unknown[] })),
   272→      });
   273→
   274→      const nodes = result.mindmap.root.children?.map((child) => convertNode(child as { id: string; text: string; color?: string; children?: unknown[] })) || [];
   275→      const subject = (result.mindmap.topic as Subject) || 'mathematics';
   276→
   277→      await saveMindmap({
   278→        title: result.mindmap.title,
   279→        nodes,
   280→        subject,
   281→      });
   282→
   283→      if (result.warnings?.length) {
   284→        alert(`Importazione completata con avvisi:\n${result.warnings.join('\n')}`);
   285→      }
   286→
   287→      logger.info('Mindmap imported', { title: result.mindmap.title, file: file.name });
   288→    } catch (error) {
   289→      logger.error('Import failed', { error, file: file.name });
   290→      alert(`Errore durante l'importazione: ${error instanceof Error ? error.message : 'Errore sconosciuto'}`);
   291→    }
   292→
   293→    // Reset input
   294→    event.target.value = '';
   295→  }, [saveMindmap]);
   296→
   297→  // Handle Escape key to close modals
   298→  useEffect(() => {
   299→    const hasOpenModal = selectedMindmap || showExamples || selectedExample || showCreateModal;
   300→    if (!hasOpenModal) return;
   301→
   302→    const handleEscape = (e: KeyboardEvent) => {
   303→      if (e.key === 'Escape') {
   304→        closeModals();
   305→      }
   306→    };
   307→    window.addEventListener('keydown', handleEscape);
   308→    return () => window.removeEventListener('keydown', handleEscape);
   309→  }, [selectedMindmap, showExamples, selectedExample, showCreateModal, closeModals]);
   310→
   311→  return (
   312→    <div className={cn('space-y-6', className)}>
   313→      {/* Header */}
   314→      <div className="flex items-center justify-between">
   315→        <div>
   316→          <h2 className="text-2xl font-bold text-slate-900 dark:text-white">
   317→            Mappe Mentali
   318→          </h2>
   319→          <p className="text-slate-600 dark:text-slate-400">
   320→            Visualizza e stampa le tue mappe create durante le lezioni
   321→          </p>
   322→        </div>
   323→        <div className="flex gap-2">
   324→          {/* PRIMARY: Conversation-first approach (Phase 6) */}
   325→          <Button onClick={() => setShowMaestroDialog(true)}>
   326→            <MessageSquare className="w-4 h-4 mr-2" />
   327→            Crea con un Professore
   328→          </Button>
   329→          {/* SECONDARY: Manual form fallback */}
   330→          <Button variant="outline" onClick={() => setShowCreateModal(true)}>
   331→            <PlusCircle className="w-4 h-4 mr-2" />
   332→            Modalità Manuale
   333→          </Button>
   334→          <Button variant="outline" onClick={() => setShowExamples(true)}>
   335→            <Sparkles className="w-4 h-4 mr-2" />
   336→            Esempi
   337→          </Button>
   338→          <Button variant="outline" asChild>
   339→            <label className="cursor-pointer">
   340→              <Upload className="w-4 h-4 mr-2" />
   341→              Importa
   342→              <input
   343→                type="file"
   344→                accept=".json,.md,.markdown,.mm,.xmind,.txt"
   345→                onChange={handleImport}
