   347→              />
   348→            </label>
   349→          </Button>
   350→        </div>
   351→      </div>
   352→
   353→      {/* Info card */}
   354→      <Card className="bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20 border-blue-200 dark:border-blue-800">
   355→        <CardContent className="p-4">
   356→          <div className="flex items-start gap-4">
   357→            <div className="p-3 rounded-xl bg-accent-themed/10">
   358→              <Network className="w-6 h-6 text-accent-themed" />
   359→            </div>
   360→            <div>
   361→              <h3 className="font-semibold text-blue-900 dark:text-blue-100 mb-1">
