   384→        <Card className="p-12">
   385→          <div className="text-center">
   386→            <Network className="w-16 h-16 mx-auto text-slate-400 mb-4" />
   387→            <h3 className="text-xl font-semibold text-slate-900 dark:text-white mb-2">
   388→              Nessuna mappa salvata
   389→            </h3>
   390→            <p className="text-slate-600 dark:text-slate-400 mb-6 max-w-md mx-auto">
   391→              Le mappe mentali create durante le sessioni vocali con i professori appariranno qui.
   392→              Prova a chiedere a un professore di creare una mappa su un argomento!
   393→            </p>
   394→            <Button variant="outline" onClick={() => setShowExamples(true)}>
   395→              <Sparkles className="w-4 h-4 mr-2" />
   396→              Esplora Esempi
   397→            </Button>
   398→          </div>
   399→        </Card>
   400→      ) : (
   401→        <div className="space-y-8">
   402→          {Object.entries(mindmapsBySubject).map(([subject, maps]) => (
   403→            <div key={subject}>
   404→              <div className="flex items-center gap-2 mb-4">
   405→                <span className="text-xl">{subjectIcons[subject as Subject]}</span>
   406→                <h3 className="text-lg font-semibold text-slate-900 dark:text-white">
   407→                  {subjectNames[subject as Subject]}
   408→                </h3>
   409→                <span className="text-sm text-slate-500">({maps.length})</span>
   410→              </div>
   411→              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
   412→                {maps.map((mindmap) => (
   413→                  <Card
   414→                    key={mindmap.id}
   415→                    className="cursor-pointer hover:shadow-lg transition-shadow group"
   416→                    onClick={() => setSelectedMindmap(mindmap)}
   417→                  >
   418→                    <CardHeader className="pb-3">
   419→                      <div className="flex items-start justify-between">
   420→                        <div className="flex items-center gap-3">
   421→                          <div
   422→                            className="w-10 h-10 rounded-xl flex items-center justify-center"
   423→                            style={{ backgroundColor: `${subjectColors[mindmap.subject]}20` }}
   424→                          >
   425→                            <Network
   426→                              className="w-5 h-5"
   427→                              style={{ color: subjectColors[mindmap.subject] }}
   428→                            />
   429→                          </div>
   430→                          <div>
   431→                            <CardTitle className="text-base">{mindmap.title}</CardTitle>
   432→                            <p className="text-xs text-slate-500">
   433→                              {new Date(mindmap.createdAt).toLocaleDateString('it-IT')}
   434→                            </p>
   435→                          </div>
   436→                        </div>
   437→                        <button
   438→                          onClick={(e) => {
   439→                            e.stopPropagation();
   440→                            handleDeleteMindmap(mindmap.id);
   441→                          }}
   442→                          className="p-2 rounded-lg hover:bg-red-100 dark:hover:bg-red-900/20 opacity-0 group-hover:opacity-100 transition-opacity"
   443→                        >
   444→                          <Trash2 className="w-4 h-4 text-red-500" />
   445→                        </button>
   446→                      </div>
   447→                    </CardHeader>
   448→                    <CardContent>
   449→                      <div className="flex flex-wrap gap-1.5">
   450→                        {mindmap.nodes.slice(0, 4).map((node, i) => (
   451→                          <span
   452→                            key={i}
   453→                            className="px-2 py-1 text-xs rounded-full bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400"
   454→                          >
   455→                            {node.label}
   456→                          </span>
   457→                        ))}
   458→                        {mindmap.nodes.length > 4 && (
   459→                          <span className="px-2 py-1 text-xs rounded-full bg-slate-100 dark:bg-slate-800 text-slate-500">
   460→                            +{mindmap.nodes.length - 4}
   461→                          </span>
   462→                        )}
   463→                      </div>
   464→                    </CardContent>
   465→                  </Card>
   466→                ))}
