   481→            onClick={() => setSelectedMindmap(null)}
   482→          >
   483→            <motion.div
   484→              initial={{ scale: 0.95 }}
   485→              animate={{ scale: 1 }}
   486→              exit={{ scale: 0.95 }}
   487→              onClick={(e) => e.stopPropagation()}
   488→              className="bg-white dark:bg-slate-900 rounded-2xl max-w-4xl w-full max-h-[90vh] overflow-hidden flex flex-col"
   489→            >
   490→              <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700">
   491→                <div className="flex items-center gap-3">
   492→                  <span className="text-xl">{subjectIcons[selectedMindmap.subject]}</span>
   493→                  <h3 className="text-xl font-bold">{selectedMindmap.title}</h3>
   494→                </div>
   495→                <div className="flex items-center gap-2">
   496→                  {/* Export dropdown */}
   497→                  <DropdownMenu>
   498→                    <DropdownMenuTrigger asChild>
   499→                      <Button variant="outline" size="sm">
   500→                        <Download className="w-4 h-4 mr-2" />
   501→                        Esporta
