                          >
                            {node.label}
                          </span>
                        ))}
                        {mindmap.nodes.length > 4 && (
                          <span className="px-2 py-1 text-xs rounded-full bg-slate-100 dark:bg-slate-800 text-slate-500">
                            +{mindmap.nodes.length - 4}
                          </span>
