                      <DropdownMenuItem onClick={() => handleExport(selectedMindmap, 'freemind')}>
                        <Network className="w-4 h-4 mr-2" />
                        FreeMind (.mm)
                      </DropdownMenuItem>
                      <DropdownMenuItem onClick={() => handleExport(selectedMindmap, 'xmind')}>
                        <Network className="w-4 h-4 mr-2" />
                        XMind
