    it('should generate unique tool IDs', async () => {
      // Mock nanoid to return different values
      const { nanoid } = await import('nanoid');
      let callCount = 0;
      vi.mocked(nanoid).mockImplementation(() => `tool-${++callCount}`);

      const args = {
        title: 'Test',
        nodes: [{ id: '1', label: 'Node', parentId: null }],
