      const result = await mindmapHandler(args, {}) as ToolExecutionResult;

      expect(result.success).toBe(true);
      const data = result.data as any;
      expect(data.nodes).toHaveLength(100);
      expect(data.markdown).toContain('# Large Mindmap');
